        val request = MAPPER.readValue("{\"messages\":[{\"content\":\"What is the weather in NYC?\",\"role\":\"user\"}],\"model\":\"gpt-4\",\"stream\":true,\"tools\":[{\"function\":{\"description\":\"Get the current weather for a given location\",\"name\":\"get_weather\",\"parameters\":{\"properties\":{\"location\":{\"description\":\"The city and state, e.g. New York, NY\",\"type\":\"string\"}},\"required\":[\"location\"],\"type\":\"object\"}},\"type\":\"function\"}]}", ChatCompletionRequest::class.java)
        val client = LiterLlm.createClient(apiKey = "test-key", baseUrl = System.getenv("MOCK_SERVER_URL") + "/fixtures/stream_with_tool_calls")
        val result = client.chatStream(request)
        val chunks = result.asSequence().toList()
        assertTrue(chunks.size >= 4, "expected >= 4 chunks")
        assertEquals("tool_calls", (if (chunks.isEmpty()) null else chunks.last().choices()?.firstOrNull()?.finishReason()?.getValue()))
        assertFalse(chunks.flatMap { c -> c.choices()?.flatMap { ch -> ch.delta()?.toolCalls() ?: emptyList() } ?: emptyList() }.isEmpty(), "expected non-empty")
        assertEquals("get_weather", chunks.flatMap { c -> c.choices()?.flatMap { ch -> ch.delta()?.toolCalls() ?: emptyList() } ?: emptyList() }.first().function().name())
        client.close()
    }

